#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int min(int a, int b) { return a < b ? a : b; }
int main() {
    int T, N, K, i, j, k, maxArea, area;
    int histogram[105];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        for (i = 0; i < N; i++) {
            scanf("%d", &histogram[i]);
        }
        maxArea = 0;
        for (i = 0; i < N; i++) {
            area = histogram[i];
            for (j = i + 1; j < N; j++) {
                if (histogram[j] >= histogram[j - 1]) {
                    area += histogram[j];
                } else if (K > 0) {
                    area += histogram[j];
                    K--;
                } else {
                    break;
                }
            }
            maxArea = max(maxArea, area);
            area = histogram[i];
            K = 0;
            for (j = i + 1; j < N; j++) {
                if (histogram[j] <= histogram[j - 1]) {
                    area += histogram[j];
                } else if (K > 0) {
                    area += histogram[j];
                    K--;
                } else {
                    break;
                }
            }
            maxArea = max(maxArea, area);
        }
        printf("%d\n", maxArea);
    }
    return 0;
}

