    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            int[] histogram = new int[N];
            for (int i = 0; i < N; i++) {
                histogram[i] = scanner.nextInt();
            }
            int maxArea = 0;
            for (int i = 0; i < N; i++) {
                int area = histogram[i];
                for (int j = i + 1; j < N; j++) {
                    if (histogram[j] >= histogram[j - 1]) {
                        area += histogram[j];
                    } else if (K > 0) {
                        area += histogram[j];
                        K--;
                    } else {
                        break;
                    }
                }
                maxArea = Math.max(maxArea, area);
                area = histogram[i];
                K = 0;
                for (int j = i + 1; j < N; j++) {
                    if (histogram[j] <= histogram[j - 1]) {
                        area += histogram[j];
                    } else if (K > 0) {
                        area += histogram[j];
                        K--;
                    } else {
                        break;
                    }
                }
                maxArea = Math.max(maxArea, area);
            }
            System.out.println(maxArea);
